```rust
fn bench_rope_insert(c: &mut Criterion) {
    let mut group = c.benchmark_group("rope_insert");

    // Insert at beginning
    group.bench_function("insert_beginning", |b| {
        let mut buffer = TextBuffer::with_text(&"x".repeat(10000));
        b.iter(|| {
            buffer.insert(0, "abc");
        })
    });

    // Insert at middle
    group.bench_function("insert_middle", |b| {
        let mut buffer = TextBuffer::with_text(&"x".repeat(10000));
        b.iter(|| {
            buffer.insert(5000, "abc");
        })
    });

    // Insert at end
    group.bench_function("insert_end", |b| {
        let mut buffer = TextBuffer::with_text(&"x".repeat(10000));
        b.iter(|| {
            buffer.insert(10000, "abc");
        })
    });

    group.finish();
}

fn bench_rope_delete(c: &mut Criterion) {
    let mut group = c.benchmark_group("rope_delete");

    group.bench_function("delete_beginning_10", |b| {
        let text = "x".repeat(10000);
        b.iter_batched(
            || TextBuffer::with_text(&text),
            |mut buffer| buffer.delete(0..10),
            BatchSize::SmallInput,
        )
    });

    group.bench_function("delete_middle_10", |b| {
        let text = "x".repeat(10000);
        b.iter_batched(
            || TextBuffer::with_text(&text),
            |mut buffer| buffer.delete(5000..5010),
            BatchSize::SmallInput,
        )
    });

    group.finish();
}
