fn bench_diff_sizes(c: &mut Criterion) {
    let mut group = c.benchmark_group("diff_sizes");

    for (w, h) in [(80, 24), (120, 40), (200, 60)] {
        let old = OptimizedBuffer::new(w, h);
        let mut new = old.clone();
        // 5% random changes
        for i in 0..(w * h / 20) as usize {
            let x = ((i * 7) % w as usize) as u32;
            let y = ((i * 13) % h as usize) as u32;
            new.set(x, y, Cell::new('X', Style::default()));
        }

        group.bench_function(format!("{w}x{h}"), |b| {
            b.iter(|| BufferDiff::compute(&old, &new))
        });
    }

    group.finish();
}
```

