            output.clear();
            for i in 0..10 {
                output.move_to(0, i);
                output.set_fg(Rgba::from_rgb_u8(i as u8 * 25, 100, 200));
                output.set_bg(Rgba::from_rgb_u8(50, i as u8 * 25, 100));
                output.set_bold(i % 2 == 0);
                output.write_str("Styled line of text here");
            }
            black_box(output.as_bytes());
        })
    });

    group.finish();
}
