### 2. Performance Baseline Script

Create `scripts/benchmark_baseline.sh`:

```bash
#\!/bin/bash
# Generate and store performance baselines
# Usage: ./scripts/benchmark_baseline.sh [baseline_name]

set -euo pipefail

BASELINE_NAME="${1:-$(git rev-parse --short HEAD)}"
BASELINE_DIR="target/criterion/baselines"
LOG_FILE="target/benchmark_${BASELINE_NAME}.log"

mkdir -p "$BASELINE_DIR"

echo "=== Generating Performance Baseline: $BASELINE_NAME ===" | tee "$LOG_FILE"
echo "Started at: $(date)" | tee -a "$LOG_FILE"
echo "Git commit: $(git rev-parse HEAD)" | tee -a "$LOG_FILE"
echo "" | tee -a "$LOG_FILE"

# Run full benchmark suite
echo "Running benchmarks..." | tee -a "$LOG_FILE"
cargo bench --message-format=json 2>&1 | tee -a "$LOG_FILE" | while read line; do
    if echo "$line" | jq -e ".reason == \"benchmark-complete\"" > /dev/null 2>&1; then
        name=$(echo "$line" | jq -r ".id")
        mean=$(echo "$line" | jq -r ".mean.estimate")
        echo "  $name: ${mean}ns" | tee -a "$LOG_FILE"
    fi
done

# Save baseline
cp -r target/criterion "$BASELINE_DIR/$BASELINE_NAME"

echo "" | tee -a "$LOG_FILE"
echo "=== Baseline saved to: $BASELINE_DIR/$BASELINE_NAME ===" | tee -a "$LOG_FILE"
echo "Completed at: $(date)" | tee -a "$LOG_FILE"
```

### 3. Regression Detection Script

Create `scripts/benchmark_regression.sh`:

```bash
#\!/bin/bash
# Compare current performance against baseline
# Usage: ./scripts/benchmark_regression.sh [baseline_name] [threshold_percent]

set -euo pipefail

BASELINE="${1:-main}"
THRESHOLD="${2:-10}"
LOG_FILE="target/benchmark_regression.log"

echo "=== Performance Regression Check ===" | tee "$LOG_FILE"
echo "Comparing against baseline: $BASELINE" | tee -a "$LOG_FILE"
echo "Regression threshold: ${THRESHOLD}%" | tee -a "$LOG_FILE"
echo "" | tee -a "$LOG_FILE"

# Run benchmarks with comparison
cargo bench -- --baseline "$BASELINE" 2>&1 | tee -a "$LOG_FILE" | while read line; do
    # Look for regression warnings
    if echo "$line" | grep -q "regressed"; then
        echo "⚠️  REGRESSION DETECTED: $line" | tee -a "$LOG_FILE"
    elif echo "$line" | grep -q "improved"; then
        echo "✅ Improvement: $line" | tee -a "$LOG_FILE"
    fi
done

# Check for regressions above threshold
REGRESSIONS=$(grep -c "regressed" "$LOG_FILE" 2>/dev/null || echo "0")

if [ "$REGRESSIONS" -gt 0 ]; then
    echo "" | tee -a "$LOG_FILE"
    echo "=== FAILED: $REGRESSIONS regressions detected ===" | tee -a "$LOG_FILE"
    exit 1
fi

echo "" | tee -a "$LOG_FILE"
echo "=== PASSED: No significant regressions ===" | tee -a "$LOG_FILE"
```

